  1	import * as React from 'react';
  2	import { SummaryTable, SummaryTableRenderer } from './BaseTable';
  3	import { IRow, ISortBy } from '@patternfly/react-table';
  4	import { RouteSummary } from '../../../types/IstioObjects';
  5	import { ActiveFilter, FILTER_ACTION_APPEND, FilterType, AllFilterTypes } from '../../../types/Filters';
  6	import { SortField } from '../../../types/SortFilters';
  7	import { Namespace } from '../../../types/Namespace';
  8	import { defaultFilter, istioConfigLink, serviceLink } from '../../../helpers/EnvoyHelpers';
  9	import { Tooltip } from '@patternfly/react-core';
 10	import { PFColors } from 'components/Pf/PfColors';
 11	import { KialiIcon } from 'config/KialiIcon';
 12	import { kialiStyle } from 'styles/StyleUtils';
 13	import { isParentKiosk } from '../../Kiosk/KioskActions';
 14	import { SortableTh } from 'components/Table/SimpleTable';
 15	import { dicTypeToGVK, gvkType } from '../../../types/IstioConfigList';
 16	
 17	export class RouteTable implements SummaryTable {
 18	  kiosk: string;
 19	  namespace: string;
 20	  namespaces: Namespace[];
 21	  sortingDirection: 'asc' | 'desc';
 22	  sortingIndex: number;
 23	  summaries: RouteSummary[];
 24	
 25	  constructor(summaries: RouteSummary[], sortBy: ISortBy, namespaces: Namespace[], namespace: string, kiosk: string) {
 26	    this.summaries = summaries;
 27	    this.sortingIndex = sortBy.index ?? 0;
 28	    this.sortingDirection = sortBy.direction ?? 'asc';
 29	    this.namespaces = namespaces;
 30	    this.namespace = namespace;
 31	    this.kiosk = kiosk;
 32	  }
 33	
 34	  availableFilters = (): FilterType[] => {
 35	    return [
 36	      {
 37	        category: 'Name',
 38	        placeholder: 'Name',
 39	        filterType: AllFilterTypes.text,
 40	        action: FILTER_ACTION_APPEND,
 41	        filterValues: []
 42	      },
 43	      {
 44	        category: 'Domains',
 45	        placeholder: 'Domains',
 46	        filterType: AllFilterTypes.text,
 47	        action: FILTER_ACTION_APPEND,
 48	        filterValues: []
 49	      }
 50	    ];
 51	  };
 52	
 53	  filterMethods = (): { [filter_id: string]: (entry: RouteSummary, filter: ActiveFilter) => boolean } => {
 54	    return {
 55	      Name: (entry: RouteSummary, filter: ActiveFilter): boolean => {
 56	        return entry.name.toString().includes(filter.value);
 57	      },
 58	      Domains: (entry: RouteSummary, filter: ActiveFilter): boolean => {
 59	        return [entry.domains.service, entry.domains.namespace, entry.domains.cluster].join('.').includes(filter.value);
 60	      }
 61	    };
 62	  };
 63	
 64	  sortFields = (): SortField<RouteSummary>[] => {
 65	    return [
 66	      {
 67	        id: 'name',
 68	        title: 'Name',
 69	        isNumeric: false,
 70	        param: 'name',
 71	        compare: (a, b) => {
 72	          return a.name.localeCompare(b.name);
 73	        }
 74	      },
 75	      {
 76	        id: 'domains',
 77	        title: 'Domains',
 78	        isNumeric: false,
 79	        param: 'doms',
 80	        compare: (a, b) => {
 81	          return [a.domains.service, a.domains.namespace, a.domains.cluster]
 82	            .join('.')
 83	            .localeCompare([b.domains.service, b.domains.namespace, b.domains.cluster].join('.'));
 84	        }
 85	      },
 86	      {
 87	        id: 'match',
 88	        title: 'Match',
 89	        isNumeric: false,
 90	        param: 'match',
 91	        compare: (a, b) => {
 92	          return a.match.localeCompare(b.match);
 93	        }
 94	      },
 95	      {
 96	        id: 'vs',
 97	        title: 'Virtual Service',
 98	        isNumeric: false,
 99	        param: 'vs',
100	        compare: (a, b) => {
101	          return a.virtual_service.localeCompare(b.virtual_service);
102	        }
103	      }
104	    ];
105	  };
106	
107	  head(): SortableTh[] {
108	    return [
109	      {
110	        title: 'Name',
111	        sortable: true
112	      },
113	      {
114	        title: 'Domains',
115	        sortable: true,
116	        info: {
117	          tooltip: (
118	            <div className={kialiStyle({ textAlign: 'left' })}>
119	              Envoy will be matched this domain to this virtual host.
120	            </div>
121	          )
122	        }
123	      },
124	      {
125	        title: 'Match',
126	        sortable: true,
127	        info: {
128	          tooltip: (
129	            <div className={kialiStyle({ textAlign: 'left' })}>
130	              The match tree to use when resolving route actions for incoming requests
131	            </div>
132	          )
133	        }
134	      },
135	      {
136	        title: 'Virtual Service',
137	        sortable: true
138	      }
139	    ];
140	  }
141	
142	  resource = (): string => 'routes';
143	
144	  setSorting = (columnIndex: number, direction: 'asc' | 'desc'): void => {
145	    this.sortingDirection = direction;
146	    this.sortingIndex = columnIndex;
147	  };
148	
149	  sortBy = (): ISortBy => {
150	    return {
151	      index: this.sortingIndex,
152	      direction: this.sortingDirection
153	    };
154	  };
155	
156	  tooltip = (): React.ReactNode => {
157	    return (
158	      <Tooltip
159	        content={
160	          <div className={kialiStyle({ textAlign: 'left' })}>
161	            Network connection between source a destination that is configured in envoy
162	          </div>
163	        }
164	      >
165	        <KialiIcon.Help className={kialiStyle({ width: '14px', height: '14px', color: PFColors.Info })} />
166	      </Tooltip>
167	    );
168	  };
169	
170	  rows(): IRow[] {
171	    const parentKiosk = isParentKiosk(this.kiosk);
172	    return this.summaries
173	      .filter((value: RouteSummary) => {
174	        return defaultFilter(value, this.filterMethods());
175	      })
176	      .sort((a: RouteSummary, b: RouteSummary) => {
177	        const sortField = this.sortFields().find((value: SortField<RouteSummary>): boolean => {
178	          return value.id === this.sortFields()[this.sortingIndex].id;
179	        });
180	
181	        return this.sortingDirection === 'asc' ? sortField!.compare(a, b) : sortField!.compare(b, a);
182	      })
183	      .map(
184	        (summary: RouteSummary): IRow => {
185	          return {
186	            cells: [
187	              summary.name,
188	              serviceLink(summary.domains, this.namespaces, this.namespace, true, parentKiosk),
189	              summary.match,
190	              istioConfigLink(summary.virtual_service, dicTypeToGVK[gvkType.VirtualService])
191	            ]
192	          };
193	        }
194	      );
195	  }
196	}
197	
198	export const RouteSummaryTable = SummaryTableRenderer<RouteTable>();

